import{c as t,Q as s,j as a,m as i}from"./chunks/framework.BBA2dIOt.js";const u=JSON.parse('{"title":"Notifications","description":"","frontmatter":{},"headers":[],"relativePath":"notifications.md","filePath":"notifications.md","lastUpdated":1780370225000}'),o={name:"notifications.md"};function n(r,e,l,c,h,p){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h1><p>Ember can push notifications to your browser or installed PWA — even when no tab is open. Notifications use the standard Web Push (VAPID) protocol, so there&#39;s no third-party push gateway in the loop: your browser talks to the push service it&#39;s already paired with (Mozilla, Google, Apple), and your Ember server is the only thing that can send to your devices.</p><h2 id="operator-setup" tabindex="-1">Operator setup <a class="header-anchor" href="#operator-setup" aria-label="Permalink to &quot;Operator setup&quot;">​</a></h2><p>There is <strong>no admin config</strong> for push. On first start Ember generates a VAPID keypair via <code>crypto/rand</code> and persists it to <code>app_settings</code>. The public key is exposed to the SPA via <code>GET /api/me/push-vapid-public-key</code>; the private key never leaves the server.</p><p>One requirement, though, is the size of a billboard:</p><blockquote><p>Service workers — the browser-side machinery push notifications run through — require a <strong>trusted TLS certificate</strong>. Self-signed / Caddy <code>tls internal</code> certs are not enough. The browser refuses to load <code>/sw.js</code> over an untrusted cert, with no override path, which means push, offline cache, and PWA install <strong>all break together</strong>.</p></blockquote><p>The error in the browser console looks like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to register a ServiceWorker for scope (&#39;https://your-host/&#39;) with</span></span>
<span class="line"><span>script (&#39;https://your-host/sw.js&#39;): An SSL certificate error occurred when</span></span>
<span class="line"><span>fetching the script.</span></span></code></pre></div><p>If you see this, you need a real cert.</p><h3 id="getting-a-real-cert-for-a-lan-deployment" tabindex="-1">Getting a real cert for a LAN deployment <a class="header-anchor" href="#getting-a-real-cert-for-a-lan-deployment" aria-label="Permalink to &quot;Getting a real cert for a LAN deployment&quot;">​</a></h3><p>The bundled <code>deploy/Caddyfile</code> gets a Let&#39;s Encrypt cert automatically when <strong>all three</strong> of these are true:</p><ol><li><code>EMBER_HOSTNAME</code> is a real DNS name pointing at the host.</li><li><code>CADDY_EMAIL</code> is a real email address.</li><li>Ports 80 / 443 are reachable from the internet (HTTP-01 / TLS-ALPN-01 challenge).</li></ol><p>For a LAN-only deployment that doesn&#39;t accept inbound public traffic, use the <strong>DNS-01 challenge</strong>. You&#39;ll need:</p><ul><li>A real domain you control (e.g. <code>example.com</code>).</li><li>An API token at your DNS provider (Cloudflare, Route53, DigitalOcean, …).</li><li>A custom Caddy build with that provider&#39;s plugin compiled in. The Caddy docs at <a href="https://caddyserver.com/docs/automatic-https#dns-challenge" target="_blank" rel="noreferrer">https://caddyserver.com/docs/automatic-https#dns-challenge</a> list the recognized providers.</li></ul><p>Then your Caddyfile becomes something like:</p><div class="language-caddy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">caddy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ember.lan.example.com {</span></span>
<span class="line"><span>  tls {</span></span>
<span class="line"><span>    dns cloudflare {env.CF_API_TOKEN}</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>  reverse_proxy ember:8080</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Caddy will request a cert via DNS-01 (which doesn&#39;t care whether anyone can reach your server, only that you control the DNS), and every device on your LAN trusts it because it chains to Let&#39;s Encrypt&#39;s public roots.</p><h3 id="why-not-just-trust-caddy-s-local-ca-on-each-device" tabindex="-1">Why not just trust Caddy&#39;s local CA on each device? <a class="header-anchor" href="#why-not-just-trust-caddy-s-local-ca-on-each-device" aria-label="Permalink to &quot;Why not just trust Caddy&#39;s local CA on each device?&quot;">​</a></h3><p>You can:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy/docker-compose.yml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> caddy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/caddy/pki/authorities/local/root.crt</span></span></code></pre></div><p>…then install the resulting certificate as a trusted root on every device you want to use Ember from. Works fine on desktops. <strong>Doesn&#39;t work well on phones</strong>: iOS requires installing the cert as a configuration profile and explicitly trusting it under Settings → General → About → Certificate Trust Settings; Android requires Settings → Security → Encryption &amp; credentials → Install a certificate → CA certificate (which also deliberately yells at you about MITM).</p><p>If push only needs to work on your laptops, the trust-the-local-CA path is acceptable. For phones, prefer DNS-01.</p><h2 id="user-flow" tabindex="-1">User flow <a class="header-anchor" href="#user-flow" aria-label="Permalink to &quot;User flow&quot;">​</a></h2><p>Once the cert situation is sorted:</p><ol><li><strong>Settings → Notifications</strong>.</li><li><strong>Enable on this device</strong> → the browser asks for notification permission.</li><li>Approve → the SPA POSTs your subscription to the server.</li><li><strong>Send test notification</strong> to confirm the round trip works.</li></ol><p>Repeat on every browser / PWA install you want to receive pushes on. The list under &quot;Registered devices&quot; shows the user-agent string and creation time of each subscription. <strong>Revoke</strong> removes the device server-side; the browser keeps a local subscription that the next push 410&#39;s on, which triggers a second server-side cleanup. Either way the row goes away.</p><h2 id="why-notifications-still-feel-sparse" tabindex="-1">Why notifications still feel sparse <a class="header-anchor" href="#why-notifications-still-feel-sparse" aria-label="Permalink to &quot;Why notifications still feel sparse&quot;">​</a></h2><p>Today push is <strong>infrastructure only</strong>: the buttons + endpoints exist but nothing yet fires a notification on its own. The next feature on the roadmap is a <code>notify</code> filter action — once that lands, a rule like &quot;<code>title contains &#39;breaking&#39;</code> → notify&quot; will push as soon as the matching article arrives. Until then push is mostly useful for verifying setup or for future hooks.</p><h2 id="what-gets-sent" tabindex="-1">What gets sent <a class="header-anchor" href="#what-gets-sent" aria-label="Permalink to &quot;What gets sent&quot;">​</a></h2><p>The payload that arrives at your service worker looks like:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;title&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Ember test&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;body&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:  </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Notifications are working.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/articles/123&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;article_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">123</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>url</code> controls what opens on notification click; <code>article_id</code> is used to collapse repeated notifications about the same article into one stack entry (the <code>tag</code> attribute on <code>showNotification</code>).</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Likely cause</th></tr></thead><tbody><tr><td>&quot;An SSL certificate error occurred when fetching the script&quot;</td><td>Untrusted TLS cert. See above.</td></tr><tr><td>&quot;Failed to register a ServiceWorker… insecure connection&quot;</td><td>Plain HTTP. Service workers require HTTPS (or <code>localhost</code>).</td></tr><tr><td>Enable button does nothing, no permission prompt</td><td>Browser permission was previously denied. Reset under the site&#39;s lock icon → Permissions → Notifications.</td></tr><tr><td>Permission granted but test send returns <code>sent: 0</code></td><td>The subscription POST failed (check Network tab) or the row was already cleaned up. Disable + re-enable.</td></tr><tr><td>Send test returns <code>sent: 1, removed: 0</code> but no notification appears</td><td>The OS is suppressing notifications (macOS Focus, iOS Focus / DND, Windows Quiet Hours). Check OS-level notification settings for your browser.</td></tr></tbody></table>`,34)])])}const k=t(o,[["render",n]]);export{u as __pageData,k as default};
